function extractDynamicUCFromCharacterPrompt(rawPrompt){
    const text = String(rawPrompt || '');
    const fields = [];
    const re = /(?:^|[;\n\r])\s*(Scene\s+UC|Character\s+\d+\s+UC)\s*:\s*([\s\S]*?)(?=(?:[;\n\r]\s*(?:Scene\s+Composition|Scene\s+UC|Character\s+\d+\s+(?:Prompt|UC|centers|coordinates))\s*:)|###|<\/image>|$)/gi;
    let m;
    while ((m = re.exec(text)) !== null) {
        const value = String(m[2] || '').trim().replace(/;+\s*$/, '').trim();
        if (value) fields.push(value);
    }
    const seen = new Set();
    const merged = [];
    for (const part of fields.join(',').split(',')) {
        const tag = part.trim();
        if (!tag) continue;
        const key = tag.toLowerCase();
        if (seen.has(key)) continue;
        seen.add(key);
        merged.push(tag);
    }
    return merged.join(', ');
}
function mergeChatu8NegativePrompt(baseNegative, dynamicNegative){
    const seen = new Set();
    const merged = [];
    for (const part of [baseNegative, dynamicNegative].filter(Boolean).join(',').split(',')) {
        const tag = String(part || '').trim();
        if (!tag) continue;
        const key = tag.toLowerCase();
        if (seen.has(key)) continue;
        seen.add(key);
        merged.push(tag);
    }
    return merged.join(', ');
}
